// Release signing: keystore + password live OUTSIDE this repo.
// Defaults point at the user-home files generated by the keystore script.
// Override via BASTION_KEYSTORE_PATH / BASTION_KEYSTORE_PASSWORD_FILE env vars
// (e.g. in CI: write the secrets to disk, then export the env vars).
val keystorePath: String = System.getenv("BASTION_KEYSTORE_PATH")
    ?: "${System.getProperty("user.home")}/bastion-mobile-release.keystore"
val keystorePasswordFile: String = System.getenv("BASTION_KEYSTORE_PASSWORD_FILE")
    ?: "${System.getProperty("user.home")}/bastion-mobile-keystore-password.txt"
val keystorePassword: String? = File(keystorePasswordFile)
    .takeIf { it.exists() }
    ?.readText()
    ?.trim()
val releaseSigningAvailable: Boolean = File(keystorePath).exists() && !keystorePassword.isNullOrEmpty()

android {
    namespace = "cam.bastion.mobile"
    compileSdk = 35

    defaultConfig {
        applicationId = "cam.bastion.mobile"
        minSdk = 26
        targetSdk = 35
        versionCode = 5
        versionName = "0.2.3"
        vectorDrawables { useSupportLibrary = true }
    }

    signingConfigs {
        if (releaseSigningAvailable) {
            create("release") {
                storeFile = File(keystorePath)
                storePassword = keystorePassword
                keyAlias = "bastion-release"
                keyPassword = keystorePassword
            }
        }
    }

    buildTypes {
        release {
            isMinifyEnabled = true
            isShrinkResources = true
            proguardFiles(getDefaultProguardFile("proguard-android-optimize.txt"), "proguard-rules.pro")
            if (releaseSigningAvailable) {
                signingConfig = signingConfigs.getByName("release")
            }
        }
        debug {
            applicationIdSuffix = ".debug"
            versionNameSuffix = "-debug"
        }
    }

    compileOptions {
        sourceCompatibility = JavaVersion.VERSION_17
        targetCompatibility = JavaVersion.VERSION_17
    }
    kotlinOptions { jvmTarget = "17" }
    buildFeatures { compose = true }
    packaging {
        resources { excludes += "/META-INF/{AL2.0,LGPL2.1}" }
    }
}

